const r = await tools.exec_command({cmd:"python3 -u - <<'PY'
import json,time,urllib.request,statistics
url='http://127.0.0.1:32000/v1/completions'
payload={'model':'/models/Qwen3.5-0.8B','prompt':' hello'*8192,'max_tokens':1024,'temperature':0,'ignore_eos':True,'stream':True,'stream_options':{'include_usage':True}}
rows=[]
for i in range(3):
 req=urllib.request.Request(url,data=json.dumps(payload).encode(),headers={'Content-Type':'application/json'})
 start=time.perf_counter(); first=None; usage=None; chunks=0
 with urllib.request.urlopen(req,timeout=900) as resp:
  for raw in resp:
   line=raw.decode().strip()
   if not line.startswith('data: ') or line=='data: [DONE]': continue
   obj=json.loads(line[6:])
   if obj.get('choices') and obj['choices'][0].get('text'):
    chunks+=1
    if first is None: first=time.perf_counter()
   if obj.get('usage'): usage=obj['usage']
 end=time.perf_counter()
 ttft=first-start; total=end-start
 out=(usage or {}).get('completion_tokens',chunks)
 throughput=(8192+out)/total
 rows.append((ttft,total,out,throughput))
 print('AITER run=%d ttft=%.4f total=%.4f output=%d total_token_throughput=%.1f tok/s' % (i+1,ttft,total,out,throughput),flush=True)
print('AITER median_ttft=%.4f median_total_throughput=%.1f' % (statistics.median(x[0] for x in rows),statistics.median(x[3] for x in rows)),flush=True)
PY",workdir:"/app",yield_time_ms:1000,max_output_tokens:8000});
text(JSON.stringify(r));

